<?php use App\Helpers\Csrf; use App\Helpers\Sanitizer; use App\Helpers\Url; $esEdicion=is_array($pieza); ?>
<main class="container"><section class="module-hero"><div><span class="eyebrow">Inventario</span><h1><?= $esEdicion?'Editar pieza':'Registrar pieza' ?></h1><p>Relaciona la pieza con su auto, tipo de parte, ubicación y fotografías.</p></div><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/inventario')) ?>">Volver</a></section><?php if(!empty($errores)): ?><div class="alerta alerta--error"><ul><?php foreach($errores as $error): ?><li><?= Sanitizer::html($error) ?></li><?php endforeach; ?></ul></div><?php endif; ?><form class="card form-wide" method="POST" enctype="multipart/form-data" action="<?= Sanitizer::html(Url::ruta($esEdicion?'/inventario/actualizar/'.$pieza['id_inventario']:'/inventario/guardar')) ?>"><?= Csrf::campo() ?><div class="form-grid"><div class="form-group"><label>Auto</label><select name="id_auto" required><option value="">Seleccione...</option><?php foreach($autos as $auto): ?><option value="<?= (int)$auto['id_auto'] ?>" <?= (int)($pieza['id_auto'] ?? 0)===(int)$auto['id_auto']?'selected':'' ?>><?= Sanitizer::html($auto['marca'].' '.$auto['modelo'].' '.$auto['anio']) ?></option><?php endforeach; ?></select></div><div class="form-group"><label>Parte</label><select name="id_parte" required><option value="">Seleccione...</option><?php foreach($partes as $parte): ?><option value="<?= (int)$parte['id_parte'] ?>" <?= (int)($pieza['id_parte'] ?? 0)===(int)$parte['id_parte']?'selected':'' ?>><?= Sanitizer::html($parte['nombre_parte']) ?></option><?php endforeach; ?></select></div><div class="form-group"><label>Sección</label><select name="id_seccion" required><option value="">Seleccione...</option><?php foreach($secciones as $seccion): ?><option value="<?= (int)$seccion['id_seccion'] ?>" <?= (int)($pieza['id_seccion'] ?? 0)===(int)$seccion['id_seccion']?'selected':'' ?>><?= Sanitizer::html($seccion['codigo'].' - '.$seccion['nombre_seccion']) ?></option><?php endforeach; ?></select></div><div class="form-group"><label>Código inventario</label><input name="codigo_inventario" required value="<?= Sanitizer::html($pieza['codigo_inventario'] ?? '') ?>" placeholder="MEC-001"></div><div class="form-group"><label>Precio</label><input type="number" step="0.01" min="0" name="precio" required value="<?= Sanitizer::html($pieza['precio'] ?? '0') ?>"></div><div class="form-group"><label>Cantidad</label><input type="number" min="0" name="cantidad" required value="<?= Sanitizer::html($pieza['cantidad'] ?? '0') ?>"></div><div class="form-group"><label>Condición</label><select name="condicion_pieza"><?php foreach($condiciones as $condicion): ?><option value="<?= Sanitizer::html($condicion) ?>" <?= ($pieza['condicion_pieza'] ?? 'Buena')===$condicion?'selected':'' ?>><?= Sanitizer::html($condicion) ?></option><?php endforeach; ?></select></div></div><div class="form-group"><label>Descripción corta</label><input name="descripcion_corta" required value="<?= Sanitizer::html($pieza['descripcion_corta'] ?? '') ?>"></div><div class="form-group"><label>Observaciones</label><textarea name="observaciones" rows="3"><?= Sanitizer::html($pieza['observaciones'] ?? '') ?></textarea></div><div class="form-grid"><div class="form-group"><label>Thumbnail</label><input type="file" name="thumbnail" accept="image/*"><?php if(!empty($pieza['thumbnail'])): ?><small>Imagen actual: <?= Sanitizer::html($pieza['thumbnail']) ?></small><?php endif; ?></div><div class="form-group"><label>Imagen grande</label><input type="file" name="imagen_grande" accept="image/*"><?php if(!empty($pieza['imagen_grande'])): ?><small>Imagen actual: <?= Sanitizer::html($pieza['imagen_grande']) ?></small><?php endif; ?></div></div><label class="check-line"><input type="checkbox" name="activo" value="1" <?= (int)($pieza['activo'] ?? 1)===1?'checked':'' ?>> Activo y visible para gestión</label><div class="form-actions"><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/inventario')) ?>">Cancelar</a><button class="btn">Guardar</button></div></form></main>
